class MemberShipModel {  bool? success;  List<MemberData>? data;  MemberShipModel({this.success, this.data});  MemberShipModel.fromJson(Map<String, dynamic> json) {    success = json['success'];    if (json['data'] != null) {      data = <MemberData>[];      json['data'].forEach((v) {        data!.add(new MemberData.fromJson(v));      });    }  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['success'] = this.success;    if (this.data != null) {      data['data'] = this.data!.map((v) => v.toJson()).toList();    }    return data;  }}class MemberData {  int? id;  String? name;  String? pointValue;  int? discountPercentage;  int? requiredPoints;  String? requiredPurchaseAmount;  String? createdAt;  String? updatedAt;  MemberData(      {this.id,        this.name,        this.pointValue,        this.discountPercentage,        this.requiredPoints,        this.requiredPurchaseAmount,        this.createdAt,        this.updatedAt});  MemberData.fromJson(Map<String, dynamic> json) {    id = json['id'];    name = json['name'];    pointValue = json['point_value'];    discountPercentage = json['discount_percentage'];    requiredPoints = json['required_points'];    requiredPurchaseAmount = json['required_purchase_amount'];    createdAt = json['created_at'];    updatedAt = json['updated_at'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['name'] = this.name;    data['point_value'] = this.pointValue;    data['discount_percentage'] = this.discountPercentage;    data['required_points'] = this.requiredPoints;    data['required_purchase_amount'] = this.requiredPurchaseAmount;    data['created_at'] = this.createdAt;    data['updated_at'] = this.updatedAt;    return data;  }}